    mapping(address => uint256) public allocation;
    mapping(address => uint256) public releaseTime;
    mapping(address => uint256) public withdrawn;

    event InvestorAdded(address indexed investor, uint256 amount, uint256 unlockTime);
    event Withdrawn(address indexed investor, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function addInvestor(address investor, uint256 amount, uint256 unlockTime) public onlyOwner {
        require(investor != address(0), "Invalid investor address");
        require(amount > 0, "Amount must be greater than 0");

        allocation[investor] = amount;
        releaseTime[investor] = unlockTime;

        emit InvestorAdded(investor, amount, unlockTime);
    }

    function withdraw() public {
        require(allocation[msg.sender] > 0, "No allocation available");
        require(block.timestamp >= releaseTime[msg.sender], "Withdrawal not yet available");

        uint256 availableAmount = allocation[msg.sender] - withdrawn[msg.sender];
        require(availableAmount > 0, "Nothing to withdraw");

        withdrawn[msg.sender] += availableAmount;
        allocation[msg.sender] = 0;

        emit Withdrawn(msg.sender, availableAmount);
    }
}
